'use client'

import React, { useMemo } from 'react'
import { ConnectionProvider, WalletProvider } from '@solana/wallet-adapter-react'
import { WalletModalProvider } from '@solana/wallet-adapter-react-ui'
import { PhantomWalletAdapter } from '@solana/wallet-adapter-wallets'
import { getSolanaNetwork, getSolanaRpcUrl } from '@/lib/solana'

require('@solana/wallet-adapter-react-ui/styles.css')

export default function Providers({ children }: { children: React.ReactNode }) {
  const network = getSolanaNetwork()
  const endpoint = getSolanaRpcUrl()

  const wallets = useMemo(() => [new PhantomWalletAdapter()], [])

  return (
    <ConnectionProvider endpoint={endpoint}>
      <WalletProvider wallets={wallets} autoConnect>
        <WalletModalProvider>{children}</WalletModalProvider>
      </WalletProvider>
    </ConnectionProvider>
  )
}

"use client"

import { useWallet } from "@solana/wallet-adapter-react"
import { useWalletModal } from "@solana/wallet-adapter-react-ui"
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu"
import { Copy, Droplet, LogOut, RefreshCw, Wallet } from "lucide-react"
import { Connection, LAMPORTS_PER_SOL } from "@solana/web3.js"
import { toast } from "sonner"
import { getSolanaRpcUrl } from "@/lib/solana"

export function CustomWalletButton() {
  const { setVisible } = useWalletModal()
  const { connected, publicKey, disconnect } = useWallet()

  const shortAddress = publicKey
    ? `${publicKey.toBase58().slice(0, 4)}...${publicKey.toBase58().slice(-4)}`
    : ""

  const requestAirdrop = async () => {
    if (!publicKey) return
    const id = toast.loading("Requesting Devnet SOL...")
    try {
      const connection = new Connection(getSolanaRpcUrl())
      const sig = await connection.requestAirdrop(publicKey, 1 * LAMPORTS_PER_SOL)
      await connection.confirmTransaction(sig)
      toast.success("1 SOL Airdropped! (Devnet)", { id })
    } catch (err: any) {
      console.error(err)
      toast.error("Airdrop failed. Faucet may be rate-limited.", { id })
    }
  }

  const copyAddress = () => {
    if (publicKey) {
      navigator.clipboard.writeText(publicKey.toBase58())
    }
  }

  if (!connected) {
    return (
      <button
        onClick={() => setVisible(true)}
        className="h-9 px-4 bg-transparent border-2 border-[#F4C542] text-[#F4C542] hover:bg-[#F4C542] hover:text-[#0B0D10] font-mono font-semibold cursor-pointer rounded-md transition-all"
      >
        Connect Wallet
      </button>
    )
  }

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <button className="h-9 px-4 bg-transparent border-2 border-[#F4C542] text-[#F4C542] hover:bg-[#F4C542] hover:text-[#0B0D10] font-mono font-semibold rounded-md transition-all">
          {shortAddress}
        </button>
      </DropdownMenuTrigger>
      <DropdownMenuContent className="bg-[#0B0D10] border border-[#F4C542]/30 text-gray-200 font-mono text-sm">
        <DropdownMenuItem onClick={copyAddress} className="flex items-center gap-2 cursor-pointer">
          <Copy className="w-4 h-4 text-[#F4C542]" /> Copy Address
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => setVisible(true)} className="flex items-center gap-2 cursor-pointer">
          <RefreshCw className="w-4 h-4 text-[#F4C542]" /> Switch Wallet
        </DropdownMenuItem>
        <DropdownMenuItem onClick={requestAirdrop} className="flex items-center gap-2 cursor-pointer border-t border-[#F4C542]/20 mt-1 pt-2">
          <Droplet className="w-4 h-4 text-[#F4C542]" /> Get Devnet SOL
          <span className="text-[9px] text-gray-500 ml-auto break-keep">DEMO</span>
        </DropdownMenuItem>
        <DropdownMenuItem onClick={disconnect} className="flex items-center gap-2 cursor-pointer text-red-500">
          <LogOut className="w-4 h-4" /> Disconnect
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

const DEFAULT_MAINNET_RPC = "https://api.mainnet-beta.solana.com"
const DEFAULT_DEVNET_RPC = "https://api.devnet.solana.com"

export function getSolanaNetwork(): "solana" | "solana-devnet" {
  return "solana-devnet"
}

export function getSolanaRpcUrl() {
  return process.env.NEXT_PUBLIC_SOLANA_RPC_DEVNET || DEFAULT_DEVNET_RPC
}
